import { writeOutput } from "./codegen";

const DOCS_URL = "https://docs.agentphone.to/api-reference";
const PLACEHOLDER_VALUE = "ap_test_c0ffee5afe10ca1c0ffee5afe10ca1c";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from AgentPhone API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:agentphone",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../contracts/firewalls";',
    "",
    "export const agentphoneFirewall = {",
    '  name: "agentphone",',
    '  description: "AgentPhone API",',
    "  placeholders: {",
    `    AGENTPHONE_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://api.agentphone.to",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Bearer ${{ secrets.AGENTPHONE_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating AgentPhone firewall config...");
  const ts = generateTypeScript();
  writeOutput("agentphone", ts, import.meta.dirname);
}
